    unique_id: `${BASE}_${object_id}`,
    state_topic,
    value_template,
    availability_topic: `${BASE}/status`,
    payload_available: "online",
    payload_not_available: "offline",
    device
  };
  if (unit) cfg.unit_of_measurement = unit;
  if (unit === 'V' && (device_class === 'voltage' || device_class === null)) {
