const BASE = flow.get('pylon_base') || 'pylontech1';
const task = msg._task || msg._task_snapshot || {};
const index = Number(task.index || 1);
const nn = String(index).padStart(2,'0');
const now = Date.now();

if (msg._invalid || msg._notPresent) return null;

// Normalize incoming frame/chunk
let text = String(msg.payload || '');
text = text.replace(/[\u21B5\u2190-\u21FF]/g,' ');

// STAT frames are typically complete (RX buffers until $$), but keep a small per-pack buffer just in case.
const key = `pylon_stat_buf_${nn}`;
let buf = flow.get(key) || '';
buf += "\n" + text;
if (buf.length > 12000) buf = buf.slice(-12000);

// Extract values
function pickNum(re){
  const m = buf.match(re);
  return m ? Number(m[1]) : null;
}

const cycles = pickNum(/CYCLE\s*Times\s*:\s*(\d+)/i);
const soh = pickNum(/(?:^|\n)\s*SOH\s*:\s*(\d+)\s*%?/i);

if (cycles === null && soh === null) {
  flow.set(key, buf);
  return null;
}

// Update pack state store
let packs = flow.get('pylon_packs') || {};
let p = packs[nn] || {};
if (cycles !== null) p.cycles = cycles;
if (soh !== null) p.soh = soh;
p.last_seen = now;
packs[nn] = p;
flow.set('pylon_packs', packs);

// Clear buffer when command completed marker appears
if (/Command completed successfully|\$\$/.test(buf)) flow.set(key, '');
else flow.set(key, buf);

// Publish to pack state topic (Discovery expects value_json.cycles/value_json.soh)
const dbg = {
  pack: nn,
  task_kind: (task.kind || null),
  cycles_found: cycles,
  soh_found: soh,
  chunk_sample: String(text).slice(0, 200)
};
const msgDbg = { topic: `${BASE}/debug/stat/${nn}`, payload: dbg, retain: false };
const msgState = { topic: `${BASE}/battery/${nn}/state`, payload: p, retain: true };
return [msgState, msgDbg];

// ===== Build Latest State daily CSV from flow memory =====
const lic = global.get('sp_license') || {};
if (!(lic.features && lic.features.csv_export)) return null;

// Source:
//   - flow.pylon_packs
//   - flow.pylon_meta
//
// Output:
//   msg.filename = /share/pylontech/pylontech_latest_state_daily_YYYY-MM-DD.csv
//   msg.payload  = header (once/day) + 1 line per pack
//
// Notes:
// - No additional RS232 polling here.
// - Uses values already parsed by the main flow.
// - Semicolon separator for Excel.
// - Decimal comma for FR Excel compatibility.

const packs = flow.get('pylon_packs') || {};
const meta  = flow.get('pylon_meta') || {};
const count = Number(meta.packs) || 0;

if (count <= 0) return null;

function pad(n){ return String(n).padStart(2,'0'); }
function toFr(val, digits){
    if (val === null || val === undefined || val === '') return '';
    const num = Number(val);
    if (!Number.isFinite(num)) return '';
    return num.toFixed(digits).replace('.', ',');
}
function toInt(val){
    const num = Number(val);
    return Number.isFinite(num) ? String(Math.round(num)) : '';
}

const now = new Date();
const day = `${now.getFullYear()}-${pad(now.getMonth()+1)}-${pad(now.getDate())}`;
const stamp = `${day} ${pad(now.getHours())}:${pad(now.getMinutes())}:${pad(now.getSeconds())}`;

let lines = [];
const headerKey = `pylon_latest_state_header_written_${day}`;
const headerDone = flow.get(headerKey) || false;

if (!headerDone) {
    lines.push('sep=;');
    lines.push('Time;pack;SOC_pct;Voltage_V;Current_A;Power_W;Temp_C;Cell_min_V;Cell_max_V;Delta_cell_mV');
    flow.set(headerKey, true);
}

// Build one row per configured pack, even if some values are missing
for (let i = 1; i <= count; i++) {
    const nn = String(i).padStart(2,'0');
    const p = packs[nn] || {};

    lines.push([
        stamp,
        i,
        toFr(p.soc, 1),
        toFr(p.voltage, 2),
        toFr(p.current, 2),
        toInt(p.power),
        toFr(p.temp, 1),
        toFr(p.cell_v_min, 3),
        toFr(p.cell_v_max, 3),
        toInt(p.cell_delta_mv)
    ].join(';'));
}

const csvDir = global.get('sp_csv_output_dir') || '/share/pylontech';
msg.filename = `${csvDir.replace(/\/$/, '')}/pylontech_latest_state_daily_${day}.csv`;
msg.payload = lines.join('\n') + '\n';
return msg;

const BASE = flow.get('pylon_base') || 'pylontech1';
const now = Date.now();

const meta = flow.get('pylon_meta') || {};
const bank = flow.get('pylon_bank') || {};
const busy = !!flow.get('pylon_busy');
const detecting = !!flow.get('pylon_detecting');

const lastRx = Number(flow.get('pylon_last_serial_rx') || 0);
const lastTx = Number(flow.get('pylon_last_serial_tx') || 0);
const lastFrame = Number(flow.get('pylon_last_frame_ok') || 0);
const lastData = Number(flow.get('pylon_last_data_seen') || 0);
const lastAgg = Number(bank.last_agg || 0);
const lastReset = Number(flow.get('pylon_watchdog_last_reset') || 0);

let status = {
  ts: now,
  busy,
  detecting,
  queue_len: (flow.get('pylon_queue') || []).length,
  last_rx_age_s: lastRx ? Math.round((now - lastRx) / 1000) : null,
  last_tx_age_s: lastTx ? Math.round((now - lastTx) / 1000) : null,
  last_frame_age_s: lastFrame ? Math.round((now - lastFrame) / 1000) : null,
  last_data_age_s: lastData ? Math.round((now - lastData) / 1000) : null,
  packs_configured: Number(meta.packs) || 0,
  highest_confirmed: Number(meta.highest_confirmed) || 0,
  state: "ok"
};

let outStatus = { topic: `${BASE}/health/serial`, payload: status, retain: true };
let outRestart = null;
let outDiscovery = null;

// Clamp ghost pack count after a grace period once real traffic confirmed fewer packs
const packs = Number(meta.packs) || 0;
const highestConfirmed = Number(meta.highest_confirmed) || 0;
const detectDoneAt = Number(meta.detect_done_at || meta.detect_started_at || 0);
if (!detecting && packs > 0 && highestConfirmed > 0 && highestConfirmed < packs) {
  const graceMs = 90 * 1000;
  if (detectDoneAt > 0 && (now - detectDoneAt) >= graceMs) {
    meta.packs = highestConfirmed;
    meta.ghost_clamped_at = now;
    flow.set('pylon_meta', meta);
    status.state = "ghost_pack_clamped";
    status.packs_configured = meta.packs;
    outStatus = { topic: `${BASE}/health/serial`, payload: status, retain: true };
    outDiscovery = { payload: true };
  }
}

// Detect stalled serial path and soft recover without restarting Node-RED
const cooldownMs = 3 * 60 * 1000;
const busyTooLong = busy && lastTx && (now - lastTx) > 20 * 1000;
const noFramesTooLong = !detecting && lastFrame && (now - lastFrame) > 120 * 1000;
const noDataTooLong = !detecting && lastAgg && (now - lastAgg) > 120 * 1000;

if ((busyTooLong || noFramesTooLong || noDataTooLong) && (now - lastReset) > cooldownMs) {
  flow.set('pylon_busy', false);
  flow.set('pylon_queue', []);
  flow.set('pylon_rx_buf', '');
  flow.set('pylon_last_task', null);
  flow.set('pylon_stat_active', null);
  flow.set('pylon_expect_stat', null);
  flow.set('pylon_watchdog_last_reset', now);

  status.state = "serial_recovery_triggered";
  status.reason = busyTooLong ? "busy_timeout" : (noFramesTooLong ? "no_frame_timeout" : "no_data_timeout");
  outStatus = { topic: `${BASE}/health/serial`, payload: status, retain: true };
  outRestart = { payload: true };
}

return [outStatus, outRestart, outDiscovery];

