  const p = line.split(/\s+/);
  if (p.length < 3) continue;

  const pctIdx = p.findIndex(v => v.endsWith('%'));
  let soc=0, sys_alarm_code='', events_flags='';
  if (pctIdx >= 0) {
    soc = parseInt(p[pctIdx].replace('%',''))||0;
    const after  = p.slice(pctIdx+1).filter(v=>v.length>0);
    const hexs   = after.filter(v=>v.startsWith('0x'));
    const nonhex = after.filter(v=>!v.startsWith('0x'));
    sys_alarm_code = hexs[hexs.length-1]  || '';
    events_flags   = nonhex[nonhex.length-1] || '';
  }

  events.push({
    item:           parseInt(p[0]),
    time:           (p[1]||'')+' '+(p[2]||''),
    voltage_V:      (parseInt(p[3])||0)/1000,
    current_A:      (parseInt(p[4])||0)/1000,
    temp_C:         (parseInt(p[5])||0)/1000,
    t_low_C:        (parseInt(p[6])||0)/1000,
