        if (!data.success) {
            node.error('Echec creation : ' + JSON.stringify(data.error));
            node.status({fill:'red', shape:'dot', text:'Erreur creation'});
            flow.set('dt_stage', 'idle');
            return null;
        }
        flow.set('dt_stage', 'await_save');
        node.status({fill:'blue', shape:'ring', text:'Injection cards...'});
        return send({ id: nextId(), type: 'lovelace/config/save', url_path: URL_PATH, config: buildConfig() });
    }

    if (stage === 'await_save') {
        if (!data.success) {
            node.error('Echec save : ' + JSON.stringify(data.error));
            node.status({fill:'red', shape:'dot', text:'Erreur save'});
            flow.set('dt_stage', 'idle');
            return null;
        }
        node.status({fill:'green', shape:'dot', text:'✅ Dashboard cree dans la sidebar'});
        flow.set('dt_stage', 'idle');
        return null;
    }

    if (stage === 'await_delete') {
        if (!data.success) {
            node.error('Echec suppression : ' + JSON.stringify(data.error));
            node.status({fill:'red', shape:'dot', text:'Erreur suppression'});
            flow.set('dt_stage', 'idle');
            return null;
        }
        node.status({fill:'grey', shape:'dot', text:'🗑 Dashboard supprime'});
        flow.set('dt_stage', 'idle');
        return null;
    }
}

return null;

// Node-RED Function Node : Poll stat 1-15 Pylontech
// Boucle stat 1 à 15 + \n pour envoi sériel
// Sortie 0 → serial-in | topic "pylontech_stat_loop"

let cmd = '';
for (let i = 1; i <= 15; i++) {
    cmd += `stat ${i}\n`;
}

msg.payload = cmd;
msg.topic = "pylontech_stat_loop";
return msg;

// Nœud Cycles amélioré (input serial lines)
if (msg.payload.includes("CYCLE Times")) {
    let match = msg.payload.match(/CYCLE Times : (\\d+)/);
    if (match) {
        let batId = flow.get("current_stat_id") || 1;  // Track via topic
        let cycles = parseInt(match[1]);
        global.set(`pylontech_bat${batId}_cycles`, cycles);
        msg.payload = {bat: batId, cycles};
        flow.set("current_stat_id", batId + 1);
    }
    return msg;
}
return null;

